export function overlaps(a, b) {
  if (!a || !b) throw new TypeError('ranges are required');
  const startA = new Date(a.start);
  const endA = new Date(a.end);
  const startB = new Date(b.start);
  const endB = new Date(b.end);

  // BUG: treats adjacent ranges as overlapping and accepts invalid ranges.
  return startA <= endB && startB <= endA;
}

export function mergeRanges(ranges) {
  return ranges
    .slice()
    .sort((a, b) => new Date(a.start) - new Date(b.start))
    .reduce((acc, range) => {
      const last = acc[acc.length - 1];
      if (last && overlaps(last, range)) {
        last.end = new Date(Math.max(new Date(last.end), new Date(range.end))).toISOString();
      } else {
        acc.push({ ...range });
      }
      return acc;
    }, []);
}

