import test from 'node:test';
import assert from 'node:assert/strict';
import { overlaps, mergeRanges } from './range.js';

test('overlaps true for real intersections', () => {
  assert.equal(overlaps({ start: '2026-01-01', end: '2026-01-10' }, { start: '2026-01-05', end: '2026-01-15' }), true);
});

test('adjacent half-open ranges do not overlap', () => {
  assert.equal(overlaps({ start: '2026-01-01', end: '2026-01-10' }, { start: '2026-01-10', end: '2026-01-15' }), false);
});

test('invalid ranges throw RangeError', () => {
  assert.throws(() => overlaps({ start: '2026-01-10', end: '2026-01-01' }, { start: '2026-01-02', end: '2026-01-03' }), RangeError);
  assert.throws(() => overlaps({ start: 'nope', end: '2026-01-01' }, { start: '2026-01-02', end: '2026-01-03' }), RangeError);
});

test('mergeRanges keeps adjacent ranges separate but merges overlaps', () => {
  assert.deepEqual(mergeRanges([
    { start: '2026-01-05T00:00:00.000Z', end: '2026-01-12T00:00:00.000Z' },
    { start: '2026-01-01T00:00:00.000Z', end: '2026-01-05T00:00:00.000Z' },
    { start: '2026-01-10T00:00:00.000Z', end: '2026-01-20T00:00:00.000Z' }
  ]), [
    { start: '2026-01-01T00:00:00.000Z', end: '2026-01-05T00:00:00.000Z' },
    { start: '2026-01-05T00:00:00.000Z', end: '2026-01-20T00:00:00.000Z' }
  ]);
});
